// CLX Outreach Generation v2 — Merge Segment Overlay (Task 2)
// Reads the lead's classified segment (residential / commercial /
// unknown) and the overlay's offer_mapping.lead_segments branch. When
// a matching branch exists, merge its pain_angles into the overlay's
// top-level pain_signals (for the prompt builder) and append a
// SEGMENT CONTEXT stanza to the claude_system_prompt so Claude knows
// the tone direction (business formal vs friendly local).
// Pass-through when overlay is missing or the segment branch absent.

const rawOverlay = $input.item.json;
const lead = $('Wait').item.json || {};

let overlay = null;
if (Array.isArray(rawOverlay) && rawOverlay.length > 0) {
  overlay = Object.assign({}, rawOverlay[0]);
} else if (rawOverlay && typeof rawOverlay === 'object' && rawOverlay.claude_system_prompt) {
  overlay = Object.assign({}, rawOverlay);
}

if (!overlay) {
  return { json: rawOverlay };
}

const segment = String(lead.lead_segment || 'unknown');
const segments = overlay.offer_mapping && overlay.offer_mapping.lead_segments;
const branch = segments && segments[segment];

if (branch) {
  const extraPains = Array.isArray(branch.pain_angles) ? branch.pain_angles : [];
  const base = Array.isArray(overlay.pain_signals) ? overlay.pain_signals : [];
  overlay.pain_signals = base.concat(extraPains);

  const tonePreamble = segment === 'commercial'
    ? 'TONE: Business formal, consultative, peer-advisor. The reader is a business owner or decision-maker. Speak to operational pressures, margin math, and org-level pain.'
    : 'TONE: Friendly, local, neighborly. The reader is a homeowner or individual. Speak to personal pressure points, convenience, and peace of mind.';

  const segmentContext = [
    '',
    'SEGMENT CONTEXT (lead_segment=' + segment + '):',
    'Target: ' + (branch.target || 'unspecified'),
    tonePreamble
  ].join('\n');

  overlay.claude_system_prompt = String(overlay.claude_system_prompt || '') + '\n\n' + segmentContext;
}

return { json: overlay };

// CLX Outreach Generation v2 — Merge Signal Context (B.9c)
// Reads the single active signal (if any) and the overlay from the
// previous Merge Segment Overlay step. If the client has
// intelligence_tier_enabled and a signal affects this vertical,
// append a MARKET CONTEXT stanza to the overlay's
// claude_system_prompt. Pass-through in every other case — this is
// backward-compatible with all pre-B.9 outreach flows.

const signalRows = $input.item.json;
const overlay = $('Merge Segment Overlay').first().json || null;
const lead = $('Wait').item.json || {};
const client = lead.clients || {};

const signals = Array.isArray(signalRows) ? signalRows : (signalRows && signalRows.id ? [signalRows] : []);
const intelligenceEnabled = client.intelligence_tier_enabled === true
  || lead.intelligence_tier_enabled === true;

// Pass through if intelligence not enabled or no signal present or
// overlay missing its prompt field (shouldn't happen post-Merge
// Segment Overlay, but defensive)
if (!intelligenceEnabled || signals.length === 0) {
  return { json: overlay };
}

const signal = signals[0];
const leadVertical = String(lead.vertical || lead.niche || 'insurance_broker');
const verticalsArr = Array.isArray(signal.affected_verticals) ? signal.affected_verticals : [];
const match = verticalsArr.find(av => av && av.vertical === leadVertical);

if (!match) {
  return { json: overlay };
}

const messaging = (match.messaging_angle || signal.messaging_angle || '').trim();
const suggestedPains = Array.isArray(match.suggested_pain_signals) ? match.suggested_pain_signals
  : (Array.isArray(signal.suggested_pain_signals) ? signal.suggested_pain_signals : []);

if (!messaging && suggestedPains.length === 0) {
  return { json: overlay };
}

const blockLines = [
  '',
  'MARKET CONTEXT (recent signal — apply naturally only if it fits this specific lead):',
  'Headline: ' + (signal.headline || ''),
  (signal.summary ? ('Summary: ' + signal.summary) : ''),
  (messaging ? ('Suggested framing: ' + messaging) : ''),
  (suggestedPains.length ? ('Pain points this signal creates: ' + suggestedPains.join(', ')) : ''),
  '',
  'IMPORTANT:',
  '- Weave this market context into the outreach naturally if it makes sense for this lead and company.',
  '- Do NOT mention the signal by headline or source — use it as framing, not as content.',
  '- If the signal does not specifically affect this lead, ignore it and use the static pain signals from the overlay.',
  '- Peer-advisor tone always wins over "current events" framing.'
].filter(Boolean).join('\n');

const nextOverlay = Object.assign({}, overlay || {});
nextOverlay.claude_system_prompt = String(nextOverlay.claude_system_prompt || '') + '\n' + blockLines;
nextOverlay._intelligence_signal_id = signal.id;
nextOverlay._intelligence_applied = true;

return { json: nextOverlay };

// CLX Outreach Generation v2 — Parse Outreach Response
// Mode: runOnceForEachItem. Null-safe: handles missing/empty response.content.

const response = $input.item.json;
const lead = $('Build Outreach Prompt').first().json;

// Safely extract text from Claude API response
let rawText = '';
if (response && response.content && Array.isArray(response.content) && response.content.length > 0) {
  rawText = response.content[0].text || '';
} else if (response && typeof response.content === 'string') {
  rawText = response.content;
}

let outreach;
if (!rawText) {
  outreach = {
    email_subject: 'A thought for ' + (lead.company || 'your business'),
    email_body: '<div style="font-family:Arial,sans-serif;font-size:15px;line-height:1.6;color:#333;max-width:600px;"><p>Hi ' + (lead.full_name || 'there') + ', I came across your work at ' + (lead.company || 'your company') + ' and thought this could be genuinely useful. Worth a quick 15-minute chat?</p></div>',
    linkedin_message: 'Hi ' + (lead.full_name || '') + ', noticed your work at ' + (lead.company || '') + ' — would love to connect.',
    whatsapp_message: 'Hi ' + (lead.full_name || '') + ', came across your business and had something relevant to share. Would you be open to a quick chat?',
    followup_message: 'Just following up on my previous message — still happy to connect if the timing works better now.',
    outreach_angle: 'Fallback outreach — empty Claude response',
    personalization_score: 1
  };
} else {
  try {
    const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
    outreach = JSON.parse(cleaned);
  } catch (e) {
    outreach = {
      email_subject: 'A thought for ' + (lead.company || 'your business'),
      email_body: 'Hi ' + (lead.full_name || 'there') + ', I came across your work at ' + (lead.company || 'your company') + ' and thought this could be genuinely useful. Worth a quick 15-minute chat?',
      linkedin_message: 'Hi ' + (lead.full_name || '') + ', noticed your work at ' + (lead.company || '') + ' — would love to connect.',
      whatsapp_message: 'Hi ' + (lead.full_name || '') + ', came across your business and had something relevant to share. Would you be open to a quick chat?',
      followup_message: 'Just following up on my previous message — still happy to connect if the timing works better now.',
      outreach_angle: 'Fallback outreach — parse error: ' + e.message,
      personalization_score: 1
    };
  }
}

const now = new Date().toISOString();

console.log('PARSE OUTREACH:', JSON.stringify({ lead_id: lead.id, has_content: !!rawText, subject: (outreach.email_subject || '').slice(0, 50) }));

return {
  json: {
    ...lead,
    email_subject: outreach.email_subject || '',
    email_body: outreach.email_body || '',
    linkedin_message: outreach.linkedin_message || '',
    whatsapp_message: outreach.whatsapp_message || '',
    followup_message: outreach.followup_message || '',
    outreach_angle: outreach.outreach_angle || '',
    personalization_score: typeof outreach.personalization_score === 'number' ? Math.round(outreach.personalization_score) : 5,
    lead_status: 'Outreach Ready',
    outreach_generated_at: now,
    updated_at: now
  }
};

// CLX Outreach Generation v2 — Prep Update Outreach

const item = $input.item.json;

const body = {
  p_lead_id: item.id,
  p_fields: {
    email_subject: item.email_subject,
    email_body: item.email_body,
    linkedin_message: item.linkedin_message,
    whatsapp_message: item.whatsapp_message,
    followup_message: item.followup_message,
    outreach_angle: item.outreach_angle,
    personalization_score: item.personalization_score,
    lead_status: 'Outreach Ready',
    outreach_generated_at: item.outreach_generated_at
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: body.p_fields.lead_status, score: item.personalization_score }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
